@startuml
skinparam classAttributeIconSize 0

class TilePyramid {
}

enum TGCEDataType <<enumeration>> {
    integer
    float
}

enum GridCellEncoding <<enumeration>> {
    grid-value-is-center
    grid-value-is-area
    grid-value-is-corner
}

class TiledGriddedCoverage {
    id : Integer
    dataType = tiles
    coverageDataType : TGCEDataType
    scale : Real
    offset : Real
    precision? : Real
    nullValue? : Real
    gridCellEncoding? : GridCellEncoding
    unitOfMeasure? : String
    fieldName? : String
    quantityDefinition? : String
}

class CoverageTile {
    scale : Real
    offset : Real
    min? : Real
    max? : Real
    mean? : Real
    standardDeviation? : Real
}

class Tile {
}

TiledGriddedCoverage --|> TilePyramid
Tile "1" *-- "*" TilePyramid
CoverageTile ..|> Tile
TiledGriddedCoverage o--> "*" CoverageTile

@enduml
